def _current_consecutive_day_count(dates: set[str], current_work_date: str) -> int:
    try:
        cursor = datetime.fromisoformat(current_work_date).date()
    except ValueError:
        return 0
    count = 0
    while cursor.isoformat() in dates:
        count += 1
        cursor -= timedelta(days=1)
    return count


