        "--allow-dws-commands",
        action="store_true",
        help=f"Explicitly allow DWS subprocess calls for this run. Without this or {DWS_COMMAND_ALLOW_ENV}=1, live collection fails closed.",
    )
    args = parser.parse_args(argv)
    if args.allow_dws_commands:
